-- Complète les champs hébreu manquants (sous-titre, description longue, SEO) sur les 10 expériences
-- créées le 2026-07-13 dans le batch GYG, où seul le titre avait été traduit en hébreu.
-- Le titre_he existant n'est pas modifié (déjà validé lors du renommage du 2026-07-15).

-- 1. Surf à Tel Aviv
UPDATE public.standalone_experiences SET
  subtitle_he = $t$שיעור גלישה פרטי, אחד על אחד, עם מדריך מוסמך בביץ' קלאב TLV, בקצה הדרומי של הטיילת.$t$,
  long_copy_he = $t$<p>שיעור גלישה פרטי בביץ' קלאב TLV, בקצה הדרומי של הטיילת בתל אביב. מדריך אחד, תלמיד אחד, והים התיכון ממש מולכם.</p>
<p>השיעור מתחיל על החול. המדריך מכין את לוח הקצף, מסביר את תנועת העמידה, את שיווי המשקל, את החתירה. הכל כלול: לוח, חליפת גלישה, וההתאמות הקטנות שעושות את ההבדל בין נפילה לתפיסת גל. אחר כך מגיע תורו של המים, תזמון הסטים, התחושה של הלוח שמתחיל לנוע מתחת לרגליים.</p>
<p>ביץ' קלאב TLV שומר על פשטות ותפקוד. מקלחות ומלתחות פרטיות מאפשרות לצאת יבשים ומסודרים, בלי מגבת ומגרש חנייה. כל השיעור נמשך כשעה, מספיק זמן להרגיש את המעבר מהניסיון הראשון הרועד לגל הראשון שנתפס.</p>
<p>בין אם כבר גלשתם או שזו הפעם הראשונה על לוח, השיעור נבנה סביב הרמה האמיתית שלכם, לא סביב תסריט קבוע. תל אביב מהמים נראית אחרת לגמרי מכל דבר אחר בעיר: קו הרקיע מתרחק, הרעש נעלם, נשארים רק הגלים והבא בתור.</p>$t$,
  seo_title_he = $t$שיעור גלישה פרטי בתל אביב | STAYMAKOM$t$,
  meta_description_he = $t$שיעור גלישה פרטי עם מדריך מוסמך בביץ' קלאב TLV. לוח, חליפה, והים התיכון, הכל כלול.$t$,
  og_title_he = $t$ללמוד לגלוש על חוף תל אביב$t$,
  og_description_he = $t$מדריך אחד, לוח אחד, שעה אחת בים התיכון. שיעור גלישה פרטי בביץ' קלאב TLV, מותאם לרמה שלכם.$t$
WHERE slug = 'private-surf-lesson-tel-aviv';

