-- 2. Bateau à fond de verre, Eilat
UPDATE public.standalone_experiences SET
  subtitle_he = $t$שייט של שעתיים בסירת זכוכית מעל שוניות האלמוגים של ים סוף, יוצא מחוף חנניה באילת.$t$,
  long_copy_he = $t$<p>שייט בסירת זכוכית לאורך מפרץ אילת. שעתיים, שלושה סיפונים, ורצפה עשויה זכוכית.</p>
<p>הסירה יוצאת מחוף חנניה ופונה אל ים סוף. בסיפון התחתון, שני מטרים מתחת לפני המים, לוחות הזכוכית נפתחים אל תוך המים: דגים נעים בלהקות רפויות, מבני אלמוגים שלוכדים את האור, סוג של עולם תת ימי שבדרך כלל דורש מסכה וסנפירים כדי לראות. הילדים מצמידים ידיים לזכוכית. אף אחד לא נרטב.</p>
<p>בסיפון העליון מחכים סיפון שמש ומקומות ישיבה מוצלים, למי שמעדיף להתבונן בקו החוף ולא באלמוגים. הקברניט מספר לאורך הדרך, מצביע על שמורת האלמוגים של אילת, הנמל הצבאי, והקו שבו ישראל נפגשת עם הגבול הירדני.</p>
<p>בר חטיפים על הסירה חוסך את הצורך לתכנן את היום סביב הרעב. משקאות, משהו לנשנש, והזמן זורם בקצב שלו.</p>
<p>שעתיים שעוברות אחרת על המים. מהסוג של אחר צהריים שמשפחה זוכרת עוד הרבה אחרי שסימני השיזוף נמחקים.</p>$t$,
  seo_title_he = $t$שייט בסירת זכוכית באילת | STAYMAKOM$t$,
  meta_description_he = $t$שייט של שעתיים בסירת זכוכית מעל שוניות האלמוגים של אילת. תצפית תת ימית ובר חטיפים כלולים.$t$,
  og_title_he = $t$לראות את ים סוף בלי להירטב$t$,
  og_description_he = $t$אלמוגים, דגים אקזוטיים, ורצפה עשויה זכוכית. שייט משפחתי של שעתיים במפרץ אילת.$t$
WHERE slug = 'glass-bottom-boat-eilat';

