-- 3. Plongée Dolphin Reef, Eilat
UPDATE public.standalone_experiences SET
  subtitle_he = $t$צלילת היכרות של שעה עם מדריך אישי בדולפין ריף אילת, עד עומק שישה מטרים, לצד דולפינים בבית הגידול הטבעי שלהם.$t$,
  long_copy_he = $t$<p>צלילת היכרות בדולפין ריף, בחוף הדרומי של אילת. ללא צורך בהסמכה, ללא ניסיון קודם בצלילה. רק מדריך אישי ושישה מטרים של ים סוף.</p>
<p>חצי השעה הראשונה מתרחשת ביבשה: התאמת חליפת צלילה וסנפירים, תדריך על השונית ואופן התנועה בה, כלל הברזל של המקום מוסבר בבירור, בלי לגעת, בלי לרדוף, בלי להאכיל. הדולפינים כאן חיים בטבע, בסביבה ימית פתוחה, והביקור נבנה סביב התבוננות בהם לפי התנאים שלהם. אחר כך המים, המדריך לצד הצולל לאורך כל הירידה, השונית שנפתחת באלמוגים ודגים חולפים, ואי שם בכחול הזה, דולפין שמתקרב מספיק כדי שישימו לב אליו.</p>
<p>מצרים נמצאת מימין לקטע החוף הזה, ירדן משמאל. צלילות הבוקר, לפני שהדולפינים מתעייפים מהחברה, נוטות להביא אותם קרוב יותר.</p>
<p>כל הצלילה נמשכת כשעה, קשת קצרה ושלמה, מהתדריך אל המים הפתוחים וחזרה, רק טעימה, אבל מהסוג שנשאר.</p>$t$,
  seo_title_he = $t$צלילת היכרות בדולפין ריף, אילת | STAYMAKOM$t$,
  meta_description_he = $t$צלילת היכרות של שעה בדולפין ריף אילת. מדריך אישי, ציוד מלא, ודולפינים חופשיים בשונית שלהם.$t$,
  og_title_he = $t$לצלול איפה שהדולפינים באמת חיים$t$,
  og_description_he = $t$אין צורך בהסמכה. מדריך אישי, שישה מטרים של ים סוף, ודולפינים שבאים והולכים כרצונם.$t$
WHERE slug = 'dolphin-reef-introductory-dive-eilat';

