-- 4. Snorkeling avec dauphins, Eilat
UPDATE public.standalone_experiences SET
  subtitle_he = $t$שנורקלינג בקבוצה קטנה, שעה אחת, בדולפין ריף אילת, שחייה החוצה למים פתוחים לצפייה בדולפינים, דגים ואלמוגים בבית הגידול שלהם.$t$,
  long_copy_he = $t$<p>שנורקלינג עם דולפינים בדולפין ריף, בחוף הדרומי של אילת. ללא הסמכת צלילה, ללא בלון חמצן, רק מסכה, שנורקל, וקבוצה קטנה שיוצאת יחד.</p>
<p>חצי מהשעה מתרחשת בחוף: התאמת מסכה, שנורקל, סנפירים וחליפה, תדריך על מה שמצפה לקבוצה בים, וכלל הברזל שחשוב כאן, הדולפינים בוחרים את האינטראקציה, לא להפך. אחר כך הקבוצה, לא יותר משלושה או ארבעה שחיינים ומדריך, יוצאת מעבר לרדוד אל המים הפתוחים, עומק של ארבעה עשר מטרים, לצוף על פני השטח בזמן שהשונית נפרשת למטה: להקות דגים שחוצות אלמוגים, ואי שם בכחול הזה, דולפינים שעסוקים בענייניהם, צדים, משחקים, ולפעמים סקרנים מספיק כדי להתקרב.</p>
<p>ילדים שכבר שוחים בביטחון מתרגלים לזה מהר. זו לא הצגה לצפות בה, אין כלום לשלוט בו, רק המים, הראות, והסבלנות לתת לשונית לבוא אליכם.</p>
<p>שעה, מהתחלה ועד הסוף, כולל תדריך. מספיק כדי לראות משהו שרוב האנשים מדמיינים רק במקום אחר, קצר מספיק כדי שכולם עדיין יחייכו ביציאה מהמים.</p>$t$,
  seo_title_he = $t$שנורקלינג עם דולפינים, אילת | STAYMAKOM$t$,
  meta_description_he = $t$שעה של שנורקלינג בדולפין ריף אילת. קבוצה קטנה, ציוד מלא, ודולפינים חופשיים במים פתוחים.$t$,
  og_title_he = $t$לצוף איפה שהדולפינים באמת שוחים$t$,
  og_description_he = $t$מסכה, שנורקל, וקבוצה קטנה שיוצאת למים פתוחים. שעה משפחתית עם דולפינים, דגים ואלמוגים.$t$
WHERE slug = 'dolphin-reef-snorkeling-eilat';

