-- 5. Vélo anti jet-lag, Tel Aviv
UPDATE public.standalone_experiences SET
  subtitle_he = $t$סיור אופניים פרטי של שלוש שעות בתל אביב וביפו, יוצא ב-6 בבוקר, לפני ההמון והחום.$t$,
  long_copy_he = $t$<p>שש בבוקר, ותל אביב עדיין שייכת למשכימי הקימה, לרצים, לדייגים שמתארגנים לאורך החוף. זו השעה שלמענה נבנה סיור האופניים ג'ט לג, כשהג'ט לג מפסיק להיות בעיה והופך ליתרון.</p>
<p>הסיור עובר שלושה מסלולים בשלוש שעות: טיילת החוף עם הים התיכון שעדיין תופס את האור הראשון, פארק הירקון שמתעורר ירוק ושקט, ואז נמל יפו העתיקה, סמטאות האבן שלה ריקות מספיק כדי לשמוע את הגלגלים שלכם על אבני הריצוף. קבוצה פרטית של עד ארבעה אנשים, מדריך שיודע בדיוק איזו פנייה לקחת לפני שהחום וההמון מדביקים, ואם עוד לא הספקתם ארוחת בוקר, יש זמן לעצירת קפה בדרך.</p>
<p>אופניים וקסדות כלולים, הקצב נשאר קליל, וכל הסיור מסתיים בדיוק במקום שבו התחיל, גמור עוד לפני שרוב העיר הספיקה את הקפה הראשון שלה.</p>
<p>למי שממילא מתעורר מוקדם מדי, הסיור הזה הופך שעון גוף שעדיין רץ על אזור זמן אחר למקום הישיבה הכי טוב בעיר.</p>$t$,
  seo_title_he = $t$סיור אופניים ג'ט לג, תל אביב | STAYMAKOM$t$,
  meta_description_he = $t$סיור אופניים פרטי ב-6 בבוקר בתל אביב וביפו, לפני ההמון והחום. אופניים, קסדות ועצירת קפה כלולים.$t$,
  og_title_he = $t$להפוך ג'ט לג למקום הישיבה הכי טוב בעיר$t$,
  og_description_he = $t$שש בבוקר, רחובות ריקים, וסיור אופניים פרטי בתל אביב וביפו לפני שהעיר מתעוררת.$t$
WHERE slug = 'jet-lag-bike-tour-tel-aviv';

