-- 6. Tel Aviv à vélo
UPDATE public.standalone_experiences SET
  subtitle_he = $t$סיור אופניים מודרך של 3 שעות בין נווה צדק, תחנת הרכבת תחנה הישנה, ושדרות רוטשילד, לאורך מאה שנות סיפור של תל אביב.$t$,
  long_copy_he = $t$<p>מעל מאה קילומטרים של שבילי אופניים חוצים את תל אביב, והסיור הזה של שלוש שעות נבנה כדי לחבר את אלה שיש להם מה לספר.</p>
<p>הוא מתחיל במתחם התחנה, תחנת הרכבת הישנה של העיר, לבנים משוחזרות ופסי רכבת שנשאו פעם את שנותיה הראשונות של תל אביב. משם, המסלול נסחף אל נווה צדק, השכונה שהתקיימה עוד לפני שאר העיר, לצד מרכז שוזאן דלל ורחובות שעדיין זוכרים שהיו הקצה של הכל. ואז שדרות רוטשילד נפתחות, רחבות ומוצלות, עד כיכר רבין, המדריך עוצר מדי פעם, לא רק כדי להצביע על בניין, אלא כדי להסביר מה הוא ייצג, ולמי, לפני שהקבוצה חוזרת אל הנמל.</p>
<p>הקצב נשאר קליל לאורך כל הדרך, אין צורך בניסיון קודם, וצלם מצטרף כדי לתפוס את הסיור מזוויות שקשה להשיג לבד עם הטלפון. עצירות תכופות מבטיחות שאף אחד לא רק דוהר על פני הסיפור, יש זמן באמת לשמוע אותו.</p>
<p>שלוש שעות, ותל אביב מפסיקה להיות עיר שמבקרים בה והופכת לעיר שעברו בה, רחוב אחר רחוב, עשור אחר עשור.</p>$t$,
  seo_title_he = $t$סיור אופניים קליל בתל אביב | STAYMAKOM$t$,
  meta_description_he = $t$סיור מודרך של 3 שעות באופניים בין נווה צדק, תחנה ושדרות רוטשילד, לאורך מאה שנות היסטוריה.$t$,
  og_title_he = $t$מאה שנות תל אביב, דיווש אחד בכל פעם$t$,
  og_description_he = $t$פסי רכבת ישנים, רחובות בוהמיינים, ושדרה שראתה את העיר גדלה. סיור אופניים מודרך של 3 שעות בתל אביב.$t$
WHERE slug = 'tel-aviv-easy-bike-tour';

