-- 7. Chocolat dans le noir, Jaffa
UPDATE public.standalone_experiences SET
  subtitle_he = $t$טעימת שוקולד של 90 דקות בחושך מוחלט במרכז נא לגעת, נמל יפו, בהובלת שוקולטייר ומדריכים עיוורים או לקויי ראייה.$t$,
  long_copy_he = $t$<p>האור כבה עוד לפני שהשוקולד מגיע. הסדנה הזו מתרחשת בחושך מוחלט, ושינוי אחד הזה משנה הכל בטעם שבו כל חתיכת שוקולד באמת נחווית.</p>
<p>פרלינים אקזוטיים במילוי, טראפלס מתובלים, והפתעות מתוקות אחרות עוברות בחדר אחת אחרי השנייה, בהובלת שוקולטייר מקצועי שעובד לצד מדריכים עיוורים או לקויי ראייה. בלי הראייה להישען עליה, המרקם מגיע קודם, אחר כך הארומה, ואז הטעם עצמו נפרש לאט יותר מהרגיל, עם יותר פרטים ממה שמבט חטוף על העטיפה היה אי פעם מציע. בין הטעימות, המדריכים מספרים על תהליך הכנת השוקולד, סוג ההכנה שרוב האנשים אף פעם לא חושבים עליה עד שהם לא יכולים לראות אותה קורית.</p>
<p>מרכז נא לגעת בנה את החוויה הזו סביב רעיון פשוט: החושך מחדד את החושים, הוא לא לוקח אותם. תשעים דקות, בהכשר, ושיחה עם המדריכים כשהאור חוזר, אם עוד נשארה שאלה על שוקולד שרק טעמתם עם הכל חוץ מהעיניים.</p>$t$,
  seo_title_he = $t$סדנת שוקולד בחושך, תל אביב | STAYMAKOM$t$,
  meta_description_he = $t$טעימת שוקולד של 90 דקות בחושך מוחלט בנא לגעת, יפו. בהובלת מדריכים עיוורים ולקויי ראייה.$t$,
  og_title_he = $t$לטעום שוקולד כמו שלא טעמתם מעולם$t$,
  og_description_he = $t$בלי אור, בלי הסחות דעת, רק מרקם, ארומה וטעם. סדנת טעימת שוקולד שמתנהלת כולה בחושך.$t$
WHERE slug = 'chocolate-tasting-workshop-in-the-dark-jaffa';

