-- 8. Dîner dans le noir, Jaffa
UPDATE public.standalone_experiences SET
  subtitle_he = $t$ארוחה בשלושה מנות המוגשת בחושך מוחלט בנמל יפו, בהובלה מלאה של מלצרים עיוורים או לקויי ראייה.$t$,
  long_copy_he = $t$<p>מזמינים את הארוחה לאור נר, ואז משאירים את הטלפון, השעון, וכל דבר שמאיר, בלוקר ליד הדלת. מה שקורה אחר כך מתרחש בחושך כה מוחלט שיש לו שם: בלאק אאוט.</p>
<p>מלצר עיוור או לקוי ראייה מחכה בסף, יד על הכתף שלו הדרך היחידה קדימה מכאן. הוא מוביל אתכם לשולחן במגע ובזיכרון, מושיב אתכם, ונשאר לאורך כל הארוחה, סבלני מול התאונות הקטנות של לאכול משהו שלא רואים, עונה לכל שאלה שעולה על איך באמת נראים החיים שלו. התפריט הכשר-חלבי כולל דג טרי, מנות צמחוניות, ואפשרות "הפתעה" למי שמוכן לנחש מה בדיוק הגיע רק לפי הריח והמרקם. בלי הראייה להישען עליה, הטעם מתחדד, וכך גם הצליל של חדר מלא זרים שאוכלים יחד בחושך, צוחקים על דברים שהיו חומקים מתשומת הלב באור.</p>
<p>ההזמנה מראש נדרשת, המושבים מתקיימים מיום ראשון עד חמישי בערב, ורבים מהאורחים משלבים את הארוחה עם ההצגה הערבית של מרכז נא לגעת, בהשתתפות שחקנים חירשים ועיוורים. בכל מקרה, כשהאור חוזר, החדר לא נראה כלל כמו מה שכל אחד דמיין בזמן שישב בו.</p>$t$,
  seo_title_he = $t$מסעדת בלאק אאוט, יפו | STAYMAKOM$t$,
  meta_description_he = $t$ארוחה בשלושה מנות בחושך מוחלט בנמל יפו, בהובלת מלצרים עיוורים. תפריט כשר-חלבי.$t$,
  og_title_he = $t$ארוחת ערב שבה אף אחד לא רואה כלום$t$,
  og_description_he = $t$בלי אור, בלי טלפון, רק טעם, קול, ומלצר עיוור שמוביל כל מנה. ארוחת ערב בבלאק אאוט, נמל יפו.$t$
WHERE slug = 'blackout-restaurant-jaffa';

