-- 9. Vélo et vin, collines de Judée
UPDATE public.standalone_experiences SET
  subtitle_he = $t$רכיבת אופניים מודרכת של ארבע שעות דרך הכרמים והמטעים של אזור עדולם, המסתיימת בטעימת יין ביקב מקומי בהרי יהודה.$t$,
  long_copy_he = $t$<p>סיור אופניים מודרך בהרי יהודה, ארבע שעות של כרמים, מטעי זיתים, ומערות חצובות בסלע, המסתיים בכוס יין שהרווחתם ביושר.</p>
<p>הרכיבה מתחילה בין הכרמים ומטעי הזיתים של אזור עדולם, לצד עצי תאנה, רימונים, וטרסות אבן יבשה שמעצבות את הגבעות האלה כבר מאות שנים. בדרך, המדריך מוביל את הקבוצה אל מערות קבורה וקולומבריום חצוב בסלע מתקופת מרד בר כוכבא, מהסוג של היסטוריה שרוב המבקרים בישראל אף פעם לא מתקרבים אליה. האופניים חזקים, בנויים לשטח, קסדות כלולות, והקצב נשאר קליל מספיק כדי לתת לנוף לדבר.</p>
<p>הרכיבה מסתיימת ביקב מקומי, שם הקבוצה מתיישבת לטעום כמה מהיינות הטובים במדינה ישר מהמקור, כשהיינן מסביר על זני הענבים ומה הופך את קטע ההרים הזה למתאים לגידולם.</p>
<p>ארבע שעות, מהתחלה ועד הסוף: אופניים, יין, והיסטוריה משולבים באחר צהריים אחד בהרים מחוץ לירושלים. מהסוג של יום שהופך את הכפר היהודאי למקום שרכבתם דרכו, לא רק הסתכלתם עליו.</p>$t$,
  seo_title_he = $t$אופניים ויין, הרי יהודה | STAYMAKOM$t$,
  meta_description_he = $t$רכיבת אופניים מודרכת של ארבע שעות בהרי יהודה. כרמים, מערות עתיקות וטעימת יין כלולים.$t$,
  og_title_he = $t$לרכוב דרך ההיסטוריה, ואז לטעום את היין$t$,
  og_description_he = $t$כרמים, מטעי זיתים, ומערות שנחצבו על ידי מורדי בר כוכבא. ארבע שעות רכיבה שמסתיימות בכוס יין יהודאי.$t$
WHERE slug = 'bike-and-wine-judean-hills';

