-- 10. Jérusalem de nuit à vélo
UPDATE public.standalone_experiences SET
  subtitle_he = $t$רכיבה מודרכת בלילה ברחובות הריקים של העיר העתיקה בירושלים, לצד שלושת אלפים שנות היסטוריה, יוצאת ב-21:30.$t$,
  long_copy_he = $t$<p>ב-21:30, כשירושלים מתחילה להתרוקן, הסיור הזה מתחיל. רחובות שבלתי אפשריים ביום, צרים מדי למכונית, צפופים מדי להליכה בקו ישר, נפתחים על שני גלגלים ברגע שהעיר נושפת החוצה ללילה.</p>
<p>הרכיבה מתחילה מחוץ לחומות, דרך הרבעים ההיסטוריים החדשים יותר, המדריך עוצר מדי פעם כדי לתת לסיפור להדביק את המקום: לא רק מה בניין הוא, אלא מה קרה שם, ולמי. אחר כך העיר העתיקה עצמה, החומות נסגרות משני הצדדים, רחובות בני אלפי שנים חולפים כמעט בשקט. כנסיית הקבר מופיעה מתוך החושך, ואז הרובע הנוצרי, הרובע היהודי, העלייה השקטה להר ציון, כל אחד שונה בלילה מכל מה שקהל יומי היה נותן לכם לראות.</p>
<p>בלי הצגה, בלי שחזור, רק ירושלים עם הרעש מושתק ומדריך שיודע בדיוק לאיזו אבן יש סיפור צמוד. כל מי שיודע לרכוב על אופניים בנוחות יכול לעשות את זה. בלי מומחיות, בלי נושא, רק עיר עתיקה מספיק כדי לזכור דברים שרוב המקומות שכחו, נראית ממושב שנותן לה לבוא אליכם לאט.</p>
<p>עד שהרכיבה מסתיימת, נשארת מפה בראש, לא של רחובות, אלא של סיפורים, מוכנה להיסלל מחדש באור יום בימים הקרובים.</p>$t$,
  seo_title_he = $t$סיור אופניים לילי בירושלים | STAYMAKOM$t$,
  meta_description_he = $t$רכיבה מודרכת בלילה בעיר העתיקה בירושלים, לצד כנסיית הקבר ורחובות בני אלפי שנים ריקים.$t$,
  og_title_he = $t$ירושלים בלילה, סיבוב גלגל אחד בכל פעם$t$,
  og_description_he = $t$רחובות ריקים, חומות עתיקות, ומדריך שמכיר כל סיפור. סיור אופניים לילי בין העיר העתיקה לירושלים החדשה.$t$
WHERE slug = 'jerusalem-night-bike-tour';

